public func shutdownGracefully() async {
    await withCheckedContinuation { continuation in
        self.state.store(.closing, ordering: .releasing)
        self.queue.async {
            self._shutdownGracefully()
            self.state.store(.closed, ordering: .releasing)
            continuation.resume()
        }
    }
}

